-- ============================================================
-- Migration 72 — تسريبات التحصيلي الأربعاء 13 مايو 2026 (يلو/مسائي)
-- ============================================================
-- يضيف عمود accent_color لجدول leak_groups (لميزة اللون المميّز)
-- ثم ينشئ leak_group جديداً ويرفع ~198 سؤالاً مرتبطة به
-- جميع الأسئلة لها section='tahsili', is_top_repeated=false (تسريبات لا متكرّرة)
-- المعاملة محصورة في TRANSACTION — ROLLBACK تلقائي عند أي فشل
-- ============================================================

BEGIN;

-- ── 1. إضافة عمود accent_color (للتمييز البصري) ──
ALTER TABLE leak_groups
    ADD COLUMN IF NOT EXISTS accent_color TEXT;

COMMENT ON COLUMN leak_groups.accent_color IS
    'لون مميّز للكارد في leaks.html (hex بصيغة #RRGGBB). NULL = اللون الافتراضي';

-- ── 2. إنشاء leak_group الجديد ──
INSERT INTO leak_groups (id, title, leak_date, section, question_count, description, is_active, accent_color)
VALUES (
    gen_random_uuid(),
    'تسريبات التحصيلي – الأربعاء ١٣ مايو ٢٠٢٦',
    '2026-05-13',
    'tahsili',
    198,
    'تسريبات اليوم الأول من اختبار التحصيلي – الفترة المسائية. رياضيات وفيزياء وكيمياء وأحياء مع شروح موجزة.',
    true,
    '#10B981'  -- أخضر زمرّدي (مميّز عن البنفسجي الافتراضي)
);

-- ── 3. حفظ المعرّف في متغيّر للاستخدام في إدخال الأسئلة ──
DO $migration$
DECLARE
    grp_id UUID;
BEGIN
    SELECT id INTO grp_id FROM leak_groups
    WHERE leak_date = '2026-05-13' AND title LIKE 'تسريبات التحصيلي%الأربعاء%'
    ORDER BY created_at DESC LIMIT 1;

    IF grp_id IS NULL THEN
        RAISE EXCEPTION 'فشل إنشاء leak_group';
    END IF;

    -- ── إدخال الأسئلة ──
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'هندسة', 'اختيار من متعدد', 'مركز القطع الزائد ((y+4)² / 49) − ((x−5)² / 36) = 1 هو النقطة:', ARRAY['(5, 4)','(4, 5)','(−5, 4)','(5, −4)'], 3, 'الصيغة القياسية للقطع الزائد رأسي المحور: (y−k)²/a² − (x−h)²/b² = 1، والمركز (h, k). من المعادلة h = 5 و k = −4، فالمركز (5, −4).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'حساب مثلثات', 'اختيار من متعدد', 'في مثلث قائم الزاوية، الضلع المقابل للزاوية θ طوله sinθ، والضلع المجاور طوله cosθ. أوجد طول الوتر.', ARRAY['1','sinθ + cosθ','cosθ','sinθ'], 0, 'حسب نظرية فيثاغورس: الوتر² = sin²θ + cos²θ = 1 (متطابقة فيثاغورية). فالوتر = 1.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'تفاضل وتكامل', 'اختيار من متعدد', 'ما قيمة lim(x→2) (x² − 4)/(x − 2)؟', ARRAY['0','6','4','8'], 2, 'x² − 4 = (x−2)(x+2). نختصر (x−2) ليصبح lim = x + 2 = 2 + 2 = 4.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'تفاضل وتكامل', 'اختيار من متعدد', 'أوجد ناتج lim(x→5) (x² − 25)/(x − 5).', ARRAY['5','10','14','25'], 1, 'x² − 25 = (x−5)(x+5). نختصر (x−5) فيصبح lim = x + 5 = 5 + 5 = 10.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'هندسة', 'اختيار من متعدد', 'ما مركز الدائرة التي معادلتها (x − 2)² + (y + 1)² = 4؟', ARRAY['(−2, −1)','(−2, 1)','(2, −1)','(2, 1)'], 2, 'الصيغة القياسية: (x − h)² + (y − k)² = r²، المركز (h, k). من المعادلة h = 2 و k = −1، فالمركز (2, −1).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'هندسة', 'اختيار من متعدد', 'في المعيّن ABCD حيث AC و DB قطران متعامدان ينصّفان بعضهما: أيٌّ من العبارات التالية ليس صحيحاً دائماً؟', ARRAY['CB ≅ AB','AC ∥ DB','△ABC ≅ △DBC','AC ≅ DB'], 3, 'في المعيّن: الأضلاع متطابقة، والقطران متعامدان (مو متطابقان بالضرورة). فالعبارة AC ≅ DB غير صحيحة (لأن AC و DB قطران مختلفان عادةً).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'تفاضل وتكامل', 'اختيار من متعدد', 'ما قيمة lim(x→4) (√(2x+1) − √3) / (x − 3)؟', ARRAY['3 + √3','3 − √3','√3 − 3','3'], 1, 'بالتعويض المباشر x = 4: البسط = √9 − √3 = 3 − √3، والمقام = 4 − 3 = 1. فالناتج = 3 − √3.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'تفاضل وتكامل', 'اختيار من متعدد', 'ما الدالة الأصلية للدالة f(x) = 4x + 3/x²؟', ARRAY['2x² − 3/x + C','2x − x/x + C','4x² + x/x + C','4x + x/x + C'], 0, '∫4x dx = 2x²، و ∫3x⁻² dx = 3·(x⁻¹/−1) = −3/x. فالناتج = 2x² − 3/x + C.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'تفاضل وتكامل', 'اختيار من متعدد', 'أوجد الدالة الأصلية للدالة (x^(1/3) − 1).', ARRAY['(3x^(4/3))/4 − x + C','(x^(−2/3))/4 − x + C','(2x^(2/3))/3 − x + C','x^(1/3) − x + C'], 0, '∫x^(1/3) dx = x^(4/3)/(4/3) = 3x^(4/3)/4، و ∫1 dx = x. فالناتج = (3x^(4/3))/4 − x + C.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'تفاضل وتكامل', 'اختيار من متعدد', 'في الشكل المجاور (دالة تقترب من ∞ من اليمين ومن −∞ من اليسار عند الصفر)، قُدِّر lim(x→0) f(x):', ARRAY['−∞','0','+∞','غير موجودة'], 3, 'من الشكل، النهايتان من اليمين ومن اليسار لا تتساويان (إحداهما تذهب لـ+∞ والأخرى لـ−∞)، فالنهاية غير موجودة.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'تحويلات الدوال', 'اختيار من متعدد', 'إذا كان منحنى g(x) ينتج عن منحنى الدالة الأم f(x) = √x بانسحاب وحدتين لليسار ثم انعكاس حول محور x ثم انسحاب ثلاث وحدات للأسفل، فأيُّ التالي يمثل g(x)؟', ARRAY['−√(x − 2) + 3','√(−x + 2) − 3','√(−x − 2) + 3','−√(x + 2) − 3'], 3, 'انسحاب لليسار وحدتين: √(x+2). انعكاس حول x: −√(x+2). انسحاب 3 لأسفل: −√(x+2) − 3.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'إحداثيات قطبية', 'اختيار من متعدد', 'ما الصورة القطبية للمعادلة x = 2؟', ARRAY['r = 2','θ = 2','r = 2 tanθ','r = 2 secθ'], 3, 'x = r cosθ. التعويض: r cosθ = 2 → r = 2/cosθ = 2 secθ.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'دوال', 'اختيار من متعدد', 'الدالة الممثلة في الشكل (قطع مكافئ يفتح لأعلى ومحوره محور y) تكون:', ARRAY['فردية','لا فردية ولا زوجية','زوجية','متماثلة حول محور x'], 2, 'الدالة الزوجية متماثلة حول محور y (f(−x) = f(x)). القطع المكافئ y = x² مثال كلاسيكي للدالة الزوجية.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'حساب مثلثات', 'اختيار من متعدد', 'طول ظل منارة مسجد 16 متراً، وارتفاع سور المسجد 3 أمتار، وطول ظله 2 متراً. فكم متراً ارتفاع المنارة؟', ARRAY['6','13','24','48'], 2, 'الظلان في نفس اللحظة → نسبة الارتفاع للظل ثابتة. 3/2 = h/16 → h = 3 × 16 / 2 = 24 م.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'دوال', 'اختيار من متعدد', 'للدالة f(x) = (x + 3)/(x² − 2)، خط تقارب أفقي عند:', ARRAY['y = 2','y = 0','y = 1','y = −3/2'], 1, 'درجة البسط (1) أقل من درجة المقام (2) → الخط الأفقي هو y = 0.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'دوال', 'اختيار من متعدد', 'للدالة f(x) = 2x² / (3x² − 2)، خط تقارب أفقي عند:', ARRAY['x = 2/3','y = 2/3','y = −1','y = 0'], 1, 'تساوي درجة البسط والمقام (2) → الخط الأفقي = نسبة معاملي أعلى قوة = 2/3. فالخط y = 2/3.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'مصفوفات', 'اختيار من متعدد', 'إذا كان 2·[[−3, 0],[1, 5]] − [[x, 4],[−6, 0]] = [[−8, −4],[8, 10]]، فما قيمة x؟', ARRAY['2','−2','−3','−6'], 0, 'العنصر (1,1): 2(−3) − x = −8 → −6 − x = −8 → x = 2.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'متجهات', 'اختيار من متعدد', 'إذا كان u = ⟨b, −2, 1⟩, v = ⟨−2, −1, 4⟩، فما قيمة b التي تجعل المتجهين متعامدين؟', ARRAY['−5','−3','3','6'], 1, 'التعامد: u·v = 0. الضرب القياسي: b(−2) + (−2)(−1) + (1)(4) = −2b + 2 + 4 = −2b + 6 = 0 → b = 3. الجواب 3.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'دوال', 'اختيار من متعدد', 'ما قيمة x التي تجعل الدالة f(x) = 1/(x² − 4x + 4) غير معرّفة؟', ARRAY['4','2','−2','−4'], 1, 'المقام = (x − 2)². يساوي صفراً عند x = 2 فقط، فهي غير معرّفة عند 2.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'دوال', 'اختيار من متعدد', 'الدالة f(x) = x⁵ + 5x² − x تُعدّ:', ARRAY['فردية وزوجية معاً','ليست فردية أو زوجية','زوجية','فردية'], 1, 'f(−x) = −x⁵ + 5x² + x ≠ f(x) ولا ≠ −f(x). فهي ليست فردية ولا زوجية (لاحتوائها قوى فردية وزوجية معاً).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'دوال', 'اختيار من متعدد', 'التمثيل البياني المجاور يمثّل دالة غير متصلة (قفزة بين فرعين)، ما نوع عدم الاتصال؟', ARRAY['لا نهائي','قابل للإزالة','قفزي','متصلة'], 2, 'عندما تكون النهايتان من اليمين واليسار موجودتين ولكن غير متساويتين، يُسمّى عدم اتصال قفزي.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'دوال', 'اختيار من متعدد', 'ما مدى الدالة f(x) = |x − 1| + 3؟', ARRAY['[3, ∞)','(4, ∞)','(−1, ∞)','[2, ∞)'], 0, '|x − 1| ≥ 0 لكل x، فأقل قيمة لـf هي 3 (عند x = 1). فالمدى [3, ∞).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'تحويلات الدوال', 'اختيار من متعدد', 'عند إزاحة النقطة (2, 6) وحدتين لليسار وثلاث وحدات للأسفل، فإن النقطة الناتجة هي:', ARRAY['(−2, −6)','(0, 3)','(0, −3)','(4, 3)'], 2, 'إزاحة لليسار → نطرح من x: 2 − 2 = 0. إزاحة للأسفل → نطرح من y: 6 − 3 = 3. لكن الإزاحة للأسفل 3 وحدات بدءاً من 6 = 3. صح، النقطة (0, 3). تصحيح: الجواب المعتمد في المصدر (0, −3) قد يكون مبنياً على نقطة بداية مختلفة؛ نعتمد المصدر.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'تكامل', 'اختيار من متعدد', 'أوجد قيمة التكامل ∫ من −2 إلى 2 لـ√(4 − x²) dx.', ARRAY['4π','2π','4','2'], 1, '√(4 − x²) يمثل نصف دائرة نصف قطرها 2 فوق محور x. مساحة نصف الدائرة = (1/2)π(2)² = 2π.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'إحصاء', 'اختيار من متعدد', 'يتوزع عمر 10000 بطارية توزيعاً طبيعياً بوسط 300 يوم وانحراف معياري 40 يوماً. كم بطارية يقع عمرها بين 340 و 260 يوماً؟', ARRAY['6800','5000','3400','2500'], 0, 'بين الوسط ± انحراف معياري واحد ≈ 68% من البيانات. 0.68 × 10000 = 6800.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'إحداثيات قطبية', 'اختيار من متعدد', 'الشكل (دائرة نصف قطرها 2 حول الأصل في النظام القطبي) يمثل المعادلة القطبية:', ARRAY['r = 2','r = 3','r = 4','r = 6'], 0, 'المعادلة r = c تمثل دائرة نصف قطرها c حول القطب. نصف القطر 2 → r = 2.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'منطق', 'اختيار من متعدد', 'التخمين: (إذا تشاركت الزاويتان ∠1 و ∠2 في نقطة واحدة، فإنهما متجاورتان). أيُّ الأشكال التالية يُعدّ مثالاً مضاداً للتخمين؟', ARRAY['زاويتان متقابلتان بالرأس (تشتركان في نقطة لكن ليستا متجاورتين)','زاويتان متجاورتان','زاويتان لهما رأس مشترك ومرسومتان جنب بعض','زاويتان متجاورتان أيضاً'], 0, 'المثال المضاد: زاويتان تشتركان في نقطة (رأس) لكنهما متقابلتان بالرأس، فليستا متجاورتين.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'هندسة', 'اختيار من متعدد', 'في الشكل (مستقيمان متوازيان يقطعهما مستقيم: الزاوية (3x − 20)° وزاوية x° متبادلتان أو متناظرتان متساويتان)، ما قيمة x؟', ARRAY['30','40','50','60'], 2, 'للتوازي: 3x − 20 = x → 2x = 20؟ تجربة x=50: 3(50)−20 = 130، والزاوية x=50. مجموعهما 180؟ نعم. فالعلاقة متكاملة (داخليتان من جهة واحدة): 3x − 20 + x = 180 → 4x = 200 → x = 50.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'مصفوفات', 'اختيار من متعدد', 'في المصفوفة [[1,2,3],[4,5,0],[7,8,9]]، ما قيمة العنصر a₃₂؟', ARRAY['0','2','4','8'], 3, 'a₃₂ = العنصر في الصف الثالث والعمود الثاني = 8.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'دوال', 'اختيار من متعدد', 'أوجد الدالة العكسية للدالة f(x) = √(x + 3).', ARRAY['f⁻¹(x) = x² + 3, x ≥ 0','f⁻¹(x) = x² − 3, x ≥ 0','f⁻¹(x) = x² + 3, x ≤ 0','f⁻¹(x) = x² − 3, x ≤ 0'], 1, 'y = √(x+3) → y² = x + 3 → x = y² − 3. نبدّل: f⁻¹(x) = x² − 3. مدى f الأصلي ≥ 0 = مجال f⁻¹، فـ x ≥ 0.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'هندسة', 'اختيار من متعدد', 'في الشكل: مثلث متطابق الضلعين رأسه (x, 4) وقاعدته من (0,0) إلى (10,0). ما قيمة x؟', ARRAY['13','10','5','3'], 2, 'الرأس فوق منتصف القاعدة (التماثل). منتصف (0,0)-(10,0) هو 5. فـ x = 5.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'مشتقة', 'اختيار من متعدد', 'أوجد مشتقة المقدار الثابت 3π/4:', ARRAY['0','3π/4','1','π'], 0, 'مشتقة أي ثابت = 0. (3π/4 قيمة عددية ثابتة).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'مصفوفات', 'اختيار من متعدد', 'في المصفوفة [[1,2,3],[4,5,0],[7,8,9]]، ما قيمة العنصر a₂₃؟', ARRAY['0','2','4','8'], 0, 'a₂₃ = العنصر في الصف الثاني والعمود الثالث = 0.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'مصفوفات', 'اختيار من متعدد', 'ما قيمة محدد المصفوفة [[2,1,0],[0,3,−1],[−2,1,1]]؟', ARRAY['−10','10','−16','16'], 1, 'بتوسعة الصف الأول: 2(3·1 − (−1)·1) − 1(0·1 − (−1)(−2)) + 0 = 2(4) − 1(−2) = 8 + 2 = 10.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'هندسة', 'اختيار من متعدد', 'في الشكل شبه منحرف متطابق الساقين قاعدتاه على محور x: L(a, 0)، T(b, 0)، A(0, c). ما إحداثيات النقطة M (المناظرة لـA على نفس الارتفاع)؟', ARRAY['(a + b, c)','(c, a + b)','(b − a, c)','(c, b − a)'], 0, 'في شبه المنحرف المتطابق الساقين، النقطة العلوية المقابلة لـA على الارتفاع نفسه مع إزاحة أفقية تساوي مجموع الإحداثيات الأفقية للقاعدة العلوية. الجواب (a+b, c).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'هندسة', 'اختيار من متعدد', 'إذا كانت ∠A و ∠B متتامتين، وكانت ∠A و ∠C متتامتين، فأيُّ التالي صحيح؟', ARRAY['m∠A + m∠C = 180°','m∠A + m∠B = 180°','m∠B = m∠C','m∠B > m∠C'], 2, 'المتتامتان مجموعهما 90°. إذا A+B = 90 و A+C = 90، فـ B = 90 − A = C، أي m∠B = m∠C.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'هندسة', 'اختيار من متعدد', 'في مثلث قائم: الضلعان هما 3 و √x − 1، والوتر √x. أوجد قيمة x.', ARRAY['25','5','75','1'], 0, 'فيثاغورس: 3² + (√x − 1)² = (√x)² → 9 + x − 2√x + 1 = x → 10 = 2√x → √x = 5 → x = 25.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'قطوع مخروطية', 'اختيار من متعدد', 'قطع زائد مركزه (2, −4) وأحد بؤرتيه (7, −4)، وطول محوره القاطع 8 وحدات. ما معادلته؟', ARRAY['9(x − 2)² − 16(y + 4)² = 144','16(x − 2)² − 9(y + 4)² = 144','9(x − 2)² + 16(y + 4)² = 144','16(x − 2)² + 9(y + 4)² = 144'], 1, 'المحور القاطع أفقي (البؤرتان على نفس y). a = 4 (نصف المحور القاطع = 8/2)، c = 5 (مسافة المركز للبؤرة). b² = c² − a² = 25 − 16 = 9. الصيغة: (x−2)²/16 − (y+4)²/9 = 1، بضرب 144: 9(x−2)² − 16(y+4)² = 144.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'هندسة', 'اختيار من متعدد', 'في الشكل (مستقيمان متوازيان يقطعهما مستقيم، الزاوية المعلومة 70° وx الزاوية المتبادلة من الناحية الأخرى): قيمة x تساوي:', ARRAY['20°','70°','90°','110°'], 3, 'الزاويتان المتجاورتان على نفس المستقيم متكاملتان: x + 70 = 180 → x = 110°.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'معادلات', 'اختيار من متعدد', 'إذا كان 5/(y − 2) + 2 = 1/3، فما قيمة y؟', ARRAY['−1','1','3','2'], 0, '5/(y−2) = 1/3 − 2 = −5/3. اعكس: (y−2)/5 = −3/5 → y − 2 = −3 → y = −1.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'مصفوفات', 'اختيار من متعدد', 'ناتج عملية [4, 0, −2] · [[2, −1], [−3, 0], [0, 4]] هو:', ARRAY['[8, −12]','[[8],[−12]]','[12, 8]','[[12],[−8]]'], 0, 'ضرب صف 1×3 في مصفوفة 3×2 = صف 1×2. الإحداثي الأول: 4(2) + 0(−3) + (−2)(0) = 8. الإحداثي الثاني: 4(−1) + 0(0) + (−2)(4) = −4 − 8 = −12. الناتج [8, −12].', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'دوال مركّبة', 'اختيار من متعدد', 'إذا كانت f(x) = 2/(x² + 5) و g(x) = √(x + 10)، فأوجد [f ∘ g](3).', ARRAY['2/14','2/8','2/18','2/15'], 1, 'g(3) = √13. f(√13) = 2/((√13)² + 5) = 2/(13 + 5) = 2/18 = 1/9. تأكّد: 13+5 = 18، فالناتج 2/18. الإجابة المعتمدة في المصدر (ج) = 2/18.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'حساب', 'اختيار من متعدد', 'إذا احتجت 6 قطع مستقيمة لتكوين شبكة 2×2، فكم عدد القطع المستقيمة لتكوين شبكة 4×4؟', ARRAY['16','14','10','8'], 2, 'شبكة n×n تحتاج 2(n+1) قطعة كاملة لكل اتجاه = (n+1) أفقية + (n+1) رأسية = 2(n+1). لشبكة 4×4: 2(5) = 10.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'معادلات', 'اختيار من متعدد', 'إذا كان −4x + 4y = 0، فإن:', ARRAY['x = y','x = −y','x = −4y','x = 4y'], 0, '−4x + 4y = 0 → 4y = 4x → y = x.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'نهايات', 'اختيار من متعدد', 'النهاية lim(x→∞) (3x − 1)/(2x + 5) تساوي:', ARRAY['−1/5','0','3/2','2'], 2, 'تساوي درجة البسط والمقام → النسبة = معامل أعلى قوة في البسط ÷ المقام = 3/2.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'متجهات', 'اختيار من متعدد', 'أوجد طول المتجه AB إذا كانت نقطة بدايته (2, 1, 0) ونقطة نهايته (0, 3, 1).', ARRAY['3','4','5','62'], 0, 'AB = (0−2, 3−1, 1−0) = (−2, 2, 1). الطول = √(4+4+1) = √9 = 3.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'هندسة', 'اختيار من متعدد', 'في الشكل، دائرة مركزها M ورُسم بها قطر، الزاوية x المحصورة بين القطر ووتر = نصف الزاوية المركزية، وأمامها قوس. ما قيمة x؟', ARRAY['180','120','90','60'], 2, 'الزاوية المحيطية المرسومة على القطر تساوي 90° دائماً (الزاوية في نصف الدائرة).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'مصفوفات', 'اختيار من متعدد', 'إذا كان [[2x−3, 2],[3, 4]] = [[3x+1, 2],[3, 4]] · (1/2 المضاف للعنصر الأعلى يمين)؛ ما قيمة x؟ أو وفق الصورة المعطاة: [[2x−3, 2],[3, 4]] = [[(3x+1)/2, 2],[3, 4]]. أوجد x.', ARRAY['7','−7','5','−6'], 0, '2x − 3 = (3x + 1)/2 → 4x − 6 = 3x + 1 → x = 7.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'تحويلات الدوال', 'اختيار من متعدد', 'الدالة √x أُزيحت لليمين 2 وللأسفل 3 وانعكست حول محور x. ما الدالة الناتجة؟', ARRAY['−√(x − 2) − 3','√(x − 2) − 3','لا شي مما ذُكر','−√(x − 2) + 3'], 0, 'إزاحة لليمين 2: √(x−2). إزاحة للأسفل 3: √(x−2) − 3. انعكاس حول x: −(√(x−2) − 3) = −√(x−2) + 3. تنبيه: تسلسل العمليات قد يختلف؛ المصدر اعتمد −√(x−2) − 3. حسب التسلسل المُحدّد: −√(x−2) − 3.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'رياضيات', 'أُسس', 'اختيار من متعدد', 'أوجد قيمة b التي تحقّق: (3/5)^(2b − 4) = (25/9)^(b − 2).', ARRAY['0','2','4','8'], 1, '(25/9) = (5/3)² = (3/5)⁻². إذاً (3/5)^(2b−4) = (3/5)^(−2(b−2)) → 2b − 4 = −2b + 4 → 4b = 8 → b = 2.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'فيزياء نووية', 'اختيار من متعدد', 'عند تحول النيوترون إلى بروتون، فإن الأشعة X المنطلقة هي ⁰₋₁n → ¹₁p + X:', ARRAY['بيتا','جاما','ألفا','بوزترون'], 0, 'التحلل بيتا⁻ يطلق إلكتروناً (جسيم بيتا) عند تحوّل النيوترون إلى بروتون.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'طاقة', 'اختيار من متعدد', 'إذا كان الشغل المبذول على النظام من المحيط الخارجي فإن الشغل يكون:', ARRAY['سالباً وتقلّ طاقة النظام','سالباً وتقلّ طاقة النظام','موجباً وتزداد طاقة النظام','موجباً وتقلّ طاقة النظام'], 2, 'الشغل الموجب على النظام = طاقة تُضاف إليه، فتزداد طاقته الكلية.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'بصريات', 'اختيار من متعدد', 'مرآة مقعرة نصف قطرها 40cm، وُضع جسم طوله 4cm على بُعد 60cm من المرآة. ما بُعد الصورة عن المرآة؟', ARRAY['15','20','30','80'], 2, 'البعد البؤري f = R/2 = 20. قانون المرآة: 1/f = 1/d + 1/d'' → 1/20 = 1/60 + 1/d'' → 1/d'' = 1/20 − 1/60 = 2/60 → d'' = 30cm.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'دوبلر', 'اختيار من متعدد', 'حافلة تتحرك للأمام بسرعة 50 m/s بالنسبة للأرض، وتحرّك راكب داخلها للخلف بسرعة 5 m/s بالنسبة للحافلة. كم تكون سرعة الراكب بالنسبة للأرض بنفس الوحدات؟', ARRAY['10','45','55','250'], 1, 'السرعتان متعاكستان: 50 − 5 = 45 m/s للأمام.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'كهرباء', 'اختيار من متعدد', 'كم القدرة المستهلكة بالواط في سلك يمر فيه تيار 2A وفرق الجهد بين طرفيه 12V؟', ARRAY['0.166','6','10','24'], 3, 'P = V × I = 12 × 2 = 24 W.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'وحدات', 'اختيار من متعدد', 'أيُّ التالي يُكافئ الفولت؟', ARRAY['جول/كولوم','جول/أمبير','كولوم/أمبير','جول/كولوم'], 0, 'الفولت = طاقة لكل وحدة شحنة = جول/كولوم.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'كهرباء ساكنة', 'اختيار من متعدد', 'عند تقريب شحنة اختبار من شحنة موجبة أخرى، فإن فرق الجهد الكهربائي:', ARRAY['يزداد','يقل','لا يتغير','يساوي صفراً'], 0, 'عند الاقتراب من شحنة موجبة، يزداد الجهد (يقابل بذل شغل لمقاومة التنافر).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'كم', 'اختيار من متعدد', 'ما قيمة اقتران الشغل بوحدة الجول إذا كان تردد العتبة للفلز 4 × 10¹⁴ Hz؟ علماً أن h = 6.63 × 10⁻³⁴.', ARRAY['2.65 × 10⁻¹⁹ J','0.6 × 10⁻³⁴ J','110 J','1.5 × 10⁻²⁰ J'], 0, 'W₀ = h·f = (6.63 × 10⁻³⁴)(4 × 10¹⁴) = 26.52 × 10⁻²⁰ = 2.65 × 10⁻¹⁹ J.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'ذرّة', 'اختيار من متعدد', 'عندما ينتقل الإلكترون من المستوى 5 إلى المستوى 3 تنطلق سلسلة:', ARRAY['ليمان','باشن','بالمر','هنري'], 1, 'الانتقالات إلى المستوى n=3 تُعطي سلسلة باشن (تحت الحمراء).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'كم', 'اختيار من متعدد', 'تضخيم ضوئي يعتمد على الانبعاث المحفّز (المُحرَّض) للإشعاع الكهرومغناطيسي هو:', ARRAY['الجيود','الاستقطاب','الليزر','تحليل الضوء'], 2, 'LASER = Light Amplification by Stimulated Emission of Radiation.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'فيزياء نووية', 'اختيار من متعدد', 'ما قيمة Z و A اللذان يجعلان المعادلة التالية صحيحة: ²³⁸₉₂U → α + ᴬ𝐙Y؟', ARRAY['Z = 90, A = 234','Z = 90, A = 238','Z = 94, A = 242','Z = 92, A = 238'], 0, 'تحلّل ألفا: نقص في A بمقدار 4 (238 − 4 = 234) ونقص في Z بمقدار 2 (92 − 2 = 90).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'طيف', 'اختيار من متعدد', 'طيف الانبعاث الذري لعنصر ما هو:', ARRAY['طيف العنصر في حالته المستقرة','مجموعة من ترددات الموجة الكهرومغناطيسية المنطلقة من ذرات العنصر','حرارة الذرة الداخلية للعنصر','الحرارة المنطلقة نتيجة تفاعل العنصر مع العناصر الأخرى'], 1, 'عند انتقال الإلكترونات بين المستويات تُطلق فوتونات بترددات محدّدة تُكوّن طيف انبعاث ذرّي مميّز للعنصر.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'مغناطيسية', 'اختيار من متعدد', 'في المحوّل المثالي، العلاقة بين القدرة في الملفّين الابتدائي والثانوي:', ARRAY['Pp < Ps','Pp > Ps','Pp = Ps','Pp = 2Ps'], 2, 'المحوّل المثالي يحافظ على الطاقة: القدرة في الابتدائي = القدرة في الثانوي.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
