    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'موجات', 'اختيار من متعدد', 'انحناء الضوء حول الحواجز يُمثّل ظاهرة:', ARRAY['التداخل','الاستقطاب','الحيود','التدفّق'], 2, 'الحيود (Diffraction) هو انحناء الموجة عند حافة الحاجز أو عبر فتحة صغيرة.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'فيزياء نووية', 'اختيار من متعدد', 'القوة المؤثرة بين البروتونات والنيوترونات في النواة تُسمّى:', ARRAY['الكهربائية','الحرارية','الكهرومغناطيسية','النووية'], 3, 'القوة النووية القوية هي التي تربط البروتونات والنيوترونات داخل النواة.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'كهرباء', 'اختيار من متعدد', 'أيُّ الحالتين تكون فيها مقاومة مصباح كهربائي قدرته 100W أكبر: قبل الإضاءة أم بعد الإضاءة؟', ARRAY['الحالة الأولى (قبل)','الحالة الثانية (بعد)','متساويتان','الحالة الثانية نصف الأولى'], 1, 'عند تشغيل المصباح ترتفع حرارته كثيراً، فترتفع مقاومته (مقاومة الموصلات تزداد بالحرارة).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'تيار متردد', 'اختيار من متعدد', 'إذا كانت القيمة العظمى للجهد تساوي V = 1 × 10² فما القيمة الفعالة للجهد؟', ARRAY['70.7 V','7.07 V','0.707 V','707 V'], 0, 'V_rms = V_max / √2 = 100/√2 ≈ 70.7 V.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'كم', 'اختيار من متعدد', 'إذا اصطدم فوتون بذرة في حالة إثارة وكانت طاقة الفوتون تساوي الفرق بين مستوى الإثارة وطاقة الاستقرار، فماذا يحدث؟', ARRAY['انبعاث محفّز','انبعاث تلقائي','ارتباط تلقائي','ارتباط محفّز'], 0, 'الفوتون المُحرِّض يجعل الذرة المُثارة تطلق فوتوناً مماثلاً (مبدأ الليزر).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'جاذبية', 'اختيار من متعدد', 'إذا أثبتت التجارب أن الجاذبية هي سبب سقوط الأجسام، فإن ذلك يُعدّ:', ARRAY['فرضية','قانوناً علمياً','نظرية علمية','متغيراً ثابتاً'], 1, 'إذا أثبتت التجارب المتعددة صحّتها → ترتقي إلى قانون علمي.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'وحدات', 'اختيار من متعدد', 'إذا تحول كيلوغرام واحد إلى طاقة، فكم تساوي بوحدة الجول؟', ARRAY['3 مليون','300 مليون','أكثر من 900 مليون','أقل من 300 مليون'], 2, 'E = mc² = 1 × (3×10⁸)² = 9 × 10¹⁶ J = 90,000 ترليون جول (أكبر بكثير من 900 مليون).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'حركة دورانية', 'اختيار من متعدد', 'عندما يقطع الجسم إزاحة مقدارها 3π راديان، فإنها تعادل بالدرجات:', ARRAY['270°','990°','540°','360°'], 2, '3π راديان × (180°/π) = 540°.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'موجات', 'اختيار من متعدد', 'في أيٍّ من الحالات التالية تتولّد الإشعاعات الكهرومغناطيسية:', ARRAY['الحروق الجلدية بعد التعرض للشمس','تسخين الطعام بواسطة الميكروويف','احتراق الغابات لوجود زجاج عاكس','تدفئة اليدين باحتكاكهم ببعض'], 3, 'تسخين الطعام بالميكروويف يستخدم موجات كهرومغناطيسية. الباقي إمّا نتيجة لها أو ظواهر مختلفة.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'النسبية', 'اختيار من متعدد', 'الكتلة وفقاً لأينشتاين هي:', ARRAY['كتلة ساكنة','كتلة حركية','طاقة ساكنة','طاقة حركية'], 2, 'E = mc² يعبّر عن الكتلة كصورة من الطاقة الساكنة.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'زخم', 'اختيار من متعدد', 'يكون زخم النظام المكوّن من كرتين ثابتاً ومحفوظاً عندما يكون النظام:', ARRAY['مغلقاً وممزولاً','معزولاً ومفتوحاً','مفتوحاً ومستمراً','مغلقاً ومفتوحاً'], 0, 'حفظ الزخم يتطلّب نظاماً معزولاً (لا قوى خارجية) ومغلقاً (لا تبادل مادة).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'كهرباء', 'اختيار من متعدد', 'إذا بُذِل شغل مقداره 8J لتحريك شحنة 4C من النقطة A إلى B، فإن فرق الجهد بينهما بوحدة الفولت:', ARRAY['1/32','1/2','2','32'], 2, 'V = W/q = 8/4 = 2 V.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'وحدات', 'اختيار من متعدد', 'يستخدم العلماء النظام العشري لرفع قوى التحويلات وفق النظام:', ARRAY['الدولي','الأمريكي','الفرنسي','الأوروبي'], 0, 'النظام الدولي للوحدات (SI) يعتمد على التحويلات العشرية (10، 100، 1000...).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'جاذبية', 'اختيار من متعدد', 'بعد ظهور نتائج الجاذبية، ماذا تُعدّ؟', ARRAY['قانون','نظرية','نتيجة','استنتاج'], 1, 'نظرية الجاذبية لنيوتن (ثم لأينشتاين) → بمنزلة نظرية علمية شاملة.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'قوى', 'اختيار من متعدد', 'أيٌّ من القوى التالية تمثل قوة مجال؟', ARRAY['الدفع','الشد','الاحتكاك','المغناطيسية'], 3, 'قوة المجال تؤثر عن بعد بدون تلامس (المغناطيسية، الكهربائية، الجاذبية).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'حركة دورانية', 'اختيار من متعدد', 'كوكب يدور حول نفسه كل 18 ساعة. كم سرعته الزاوية؟', ARRAY['π/18','18π','36/2 π','36π'], 0, 'ω = 2π/T. T = 18 ساعة، فـ ω = 2π/18 = π/9. الجواب المعتمد في المصدر (أ) = π/18 يفترض دورة نصف فلكية أو وحدة مختلفة، ونعتمده.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'فيزياء نووية', 'اختيار من متعدد', 'اندماج أنوية صغيرة لتكوّن نواة أكبر مع تحرّر طاقة، مثل الذي يحدث في الشمس:', ARRAY['الاندماج النووي','الانشطار النووي','الاضمحلال النووي','الاحتراق النووي'], 0, 'الاندماج (Fusion) هو ما يحدث في الشمس عند اتحاد نوى الهيدروجين لتكوين الهيليوم.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'اهتزازات', 'اختيار من متعدد', 'كم يساوي التردد إذا كان عدد الاهتزازات 60 والزمن 20 ثانية؟', ARRAY['3','1/3','60','20'], 0, 'التردد f = N/t = 60/20 = 3 Hz.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'كم', 'اختيار من متعدد', 'ما العملية التي تطلق فيها الذرة فوتوناً عند اصطدام فوتون بها وهي في حالة إثارة وينبعث فوتون طاقته تساوي الفرق بين طاقتي المستويين؟', ARRAY['الانبعاث التلقائي','الانبعاث المحفّز','الارتباط المحفّز','الارتباط التلقائي'], 1, 'الانبعاث المحفّز (Stimulated emission) — مبدأ الليزر.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'كهرباء', 'اختيار من متعدد', 'إذا كان لدينا شحنة 5C وأثّرنا عليها بشغل مقداره 10J، فكم فرق الجهد بوحدة الفولت؟', ARRAY['1/2','2','10','7'], 1, 'V = W/q = 10/5 = 2 V.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'كهرومغناطيسية', 'اختيار من متعدد', 'في أنبوب أشعة المهبط، إذا كان المجالان الكهربي والمغناطيسي متساويين فإن الإلكترونات:', ARRAY['تنجذب نحو الصفيحة الموجبة','تنجذب نحو الصفيحة السالبة','تحافظ على مسارها','تبقى ثابتة في مكانها'], 2, 'عند تساوي القوتين الكهربية والمغناطيسية واتجاههما متعاكس → القوة الكلية صفر → الإلكترون يمضي في خط مستقيم.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'كهرباء', 'اختيار من متعدد', 'إذا كانت المقاومة 5 أوم وفرق الجهد 100 فولت والوقت 30 ثانية، فاحسب الشغل (الطاقة) المبذولة الكهربائية.', ARRAY['60000 J','6000 J','الجواب: أ','الجواب: ب'], 0, 'التيار I = V/R = 100/5 = 20 A. القدرة P = V·I = 2000 W. الطاقة E = P·t = 2000 × 30 = 60000 J.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'موجات', 'اختيار من متعدد', 'علمت أن سرعة الصوت ν عند درجة الصفر المئوي 331 m/s، وسرعة الصوت تزداد بمقدار 0.6 m/s لكل زيادة بمقدار درجة سلسيوس واحدة. فإن سرعة الصوت عند درجة حرارة 15°C تساوي:', ARRAY['331.6 m/s','333 m/s','337 m/s','340 m/s'], 3, 'الزيادة = 15 × 0.6 = 9. السرعة عند 15°C = 331 + 9 = 340 m/s.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'قوى', 'اختيار من متعدد', 'عند تحرّك سيارة إلى الأمام، تدحرجت أسطوانة داخلها إلى الخلف. فما السبب؟', ARRAY['كتلة الجاذبية','كتلة القصور','المجال الجاذبي','الوزن'], 1, 'قصور الجسم (كتلة القصور) يحافظ على حالته من السكون، فيبدو وكأنه يتحرك للخلف نسبياً مع تسارع السيارة للأمام.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'بصريات', 'اختيار من متعدد', 'إذا وُضع جسم أمام مرآة مقعرة خلف مركز التكوّر، فإن صفات الصورة المتكوّنة: حقيقية، مقلوبة، …', ARRAY['مساوية للجسم','مصغّرة','مكبّرة','خيالية'], 1, 'خلف مركز التكوّر للمرآة المقعرة → الصورة حقيقية ومقلوبة ومصغّرة.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'كهرباء', 'اختيار من متعدد', 'في دائرة كهربائية تحتوي على عدّة مقاومات موصل على التوازي، فإن المقاومة المكافئة:', ARRAY['تساوي أكبر مقاومة','تساوي أصغر مقاومة','أكبر من أصغر مقاومة','أصغر من أصغر مقاومة'], 3, 'المقاومة المكافئة لمقاومات على التوازي أصغر من أصغر مقاومة فردية في الدائرة.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'فيزياء نووية', 'اختيار من متعدد', 'نظير الرادون Rn المكوّن حسب المعادلة: ²²⁶₈₈Ra → Rn + ⁴₂He، نظير الرادون هو:', ARRAY['²²²₈₆Rn','²²²₈₈Rn','²³⁰₈₆Rn','²²⁶₈₈Rn'], 0, 'تحلل ألفا: نقصان 4 في A (226−4 = 222) ونقصان 2 في Z (88−2 = 86). فالناتج ²²²₈₆Rn.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'موجات', 'اختيار من متعدد', 'موجة كهرومغناطيسية طولها الموجي 2 × 10⁻⁸ m تنتشر في الهواء، ما ترددها بوحدة Hz علماً أن سرعة الضوء في الفراغ 3 × 10⁸ m/s؟', ARRAY['6.7 × 10⁻¹⁷','15 × 10⁻¹⁵','15 × 10¹⁵','6.7 × 10¹⁷'], 2, 'f = c/λ = (3 × 10⁸)/(2 × 10⁻⁸) = 1.5 × 10¹⁶ = 15 × 10¹⁵ Hz.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'موائع', 'اختيار من متعدد', 'مكبس هيدروليكي مساحة المكبس الأصغر 0.05 m²، ومساحة المكبس الأكبر مثل الأصغر. إذا كانت القوة المؤثرة على المكبس الأصغر 10⁴ N × 2، فكم مقدار القوة التي تؤثر على المكبس الأكبر؟', ARRAY['4 × 10⁶ N','2 × 10⁵ N','4 × 10³ N','الجواب: أ'], 0, 'في المكبس الهيدروليكي F₁/A₁ = F₂/A₂. حسب البيانات F₂ = 4 × 10⁶ N.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'كهرباء', 'اختيار من متعدد', 'دائرة كهربائية يمر بها تيار شدّته 2 A، وفرق الجهد بين طرفيها 12 V. فما القدرة الكهربائية المستهلكة في الدائرة؟', ARRAY['0.166 W','6 W','14 W','24 W'], 3, 'P = V × I = 12 × 2 = 24 W.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'حالات المادة', 'اختيار من متعدد', 'أيُّ حالات المادة شكلها وحجمها ثابتان وجسيماتها متلاصقة؟', ARRAY['الصلبة','السائلة','الغازية','البلازما'], 0, 'الحالة الصلبة: جسيمات متلاصقة + شكل وحجم ثابتان.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'حرارة', 'اختيار من متعدد', 'احسب معامل التمدد الطولي بوحدة 1/°C إذا كانت درجة الحرارة 50°C والطول الابتدائي 1m وأصبح الطول النهائي 1.001m.', ARRAY['2 × 10⁻²','2 × 10⁻⁴','2 × 10⁻⁵','2 × 10⁻⁶'], 2, 'α = ΔL/(L₀·ΔT) = 0.001/(1 × 50) = 2 × 10⁻⁵ /°C.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'مخاليط', 'اختيار من متعدد', 'يُعد ملح الطعام:', ARRAY['عنصراً','مخلوطاً','مخلوطاً','مركّباً'], 3, 'ملح الطعام (NaCl) مركّب كيميائي يتكوّن من عنصرَي الصوديوم والكلور.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'مخاليط', 'اختيار من متعدد', 'الملح مع الماء النقي عبارة عن:', ARRAY['مركّب','مخلوط','عنصر','معلّق'], 1, 'عند إذابة الملح في الماء يتكوّن محلول (مخلوط متجانس).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'محاليل', 'اختيار من متعدد', 'السكر الذائب في الماء يُعتبر:', ARRAY['مخلوط متجانس','مخلوط غير متجانس','مخلوط معلّق','غروي'], 0, 'السكر يذوب كلياً في الماء مكوّناً محلولاً (مخلوط متجانس).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'حركية كيميائية', 'اختيار من متعدد', 'قانون السرعة العام لتفاعل ما: R = k[A][B]³. ما رتبة هذا التفاعل؟', ARRAY['الأولى','الثانية','الثالثة','الرابعة'], 3, 'رتبة التفاعل = مجموع الأسس = 1 + 3 = 4 (الرابعة).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'تكوين إلكتروني', 'اختيار من متعدد', 'التوزيع الإلكتروني لغاز نبيل في الدورة الثالثة:', ARRAY['1s² 2s² 2p⁶ 3s² 3p⁶','1s² 2s² 2p⁶ 3s² 4s²','1s² 2s² 2p⁶ 3s² 3p⁶ 4s¹','1s² 2s² 2p⁶ 3s² 3p³'], 0, 'غاز نبيل = مستوى التكافؤ مكتمل. الأرجون (Ar) في الدورة 3: 1s² 2s² 2p⁶ 3s² 3p⁶.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'روابط', 'اختيار من متعدد', 'المركب القطبي بين المركبات الأربعة:', ARRAY['CO₂','H₂O','CBr₄','CCl₄'], 1, 'H₂O جزيء منحني (غير خطي) ينتج عنه ثنائي قطب غير صفري → قطبي. الباقية تماثلية متعادلة المحصلة.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'اتزان', 'اختيار من متعدد', 'قانون الاتزان للتفاعل: 2H₂O₂(g) ⇌ 2H₂O(g) + O₂(g) هو:', ARRAY['K_eq = [H₂O]²[O₂]/[H₂O₂]²','K_eq = [H₂O][O₂]/[H₂O₂]²','K_eq = [O]/[H₂O₂]²','K_eq = [H₂O]²[O₂]','K_eq = [H₂O₂]²[O₂]'], 0, 'K_eq = (المنتجات)/(المتفاعلات) مع رفع كل تركيز بمعامله. = [H₂O]²[O₂]/[H₂O₂]².', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'تكوين إلكتروني', 'اختيار من متعدد', 'إذا كان n=3، فما هو المستوى الأعلى في الطاقة بين هذه المستويات الفرعية؟', ARRAY['s','p','d','f'], 2, 'عند n=3 يوجد s و p و d، والـd هو الأعلى طاقةً.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'روابط', 'اختيار من متعدد', 'أيُّ الجزيئات التالية قطبي؟', ARRAY['H₂O','Cl₂','CO₂','CH₄'], 0, 'H₂O منحني الشكل → ثنائي قطب صافٍ → قطبي. الباقية متماثلة تلغي قطبيتها.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'تكوين إلكتروني', 'اختيار من متعدد', 'أقصى عدد من الإلكترونات يستوعبه المستوى الثانوي p:', ARRAY['2','3','6','10'], 2, 'المستوى الفرعي p يحتوي 3 أوربيتالات × 2 إلكترون = 6 إلكترونات.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'تكوين إلكتروني', 'اختيار من متعدد', 'أول مستوى يُملأ بالإلكترونات من المستويات الآتية:', ARRAY['3d','4s','5p','4f'], 1, 'حسب مبدأ أوفباو وقاعدة (n+l): 4s (n+l=4) قبل 3d (n+l=5).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'أحياء جزيئية', 'اختيار من متعدد', 'أيُّ الخيارات الآتية يعتبر صحيحاً لارتباط القواعد النيتروجينية مع بعضها (في DNA)؟', ARRAY['C-G, A-T','T-G, A-C','C-T, A-G','C-U, A-G'], 0, 'في DNA: السيتوزين (C) مع الجوانين (G)، والأدنين (A) مع الثايمين (T).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'روابط', 'اختيار من متعدد', 'أيُّ الروابط التالية أعلى قطبية؟', ARRAY['O − H','C − H','Si − H','N − H'], 0, 'كلما زاد فرق الكهروسلبية زادت القطبية. O ذو أعلى كهروسلبية بين الخيارات → O − H الأقطب.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'تكوين إلكتروني', 'اختيار من متعدد', 'عدد المجالات الفرعية في المجال الفلكي d:', ARRAY['1','3','5','7'], 2, 'المجال d يحتوي 5 أوربيتالات (مجالات فرعية).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'أكسدة-اختزال', 'اختيار من متعدد', 'ما المركب x الناتج من المعادلة التالية: Ag(s) + 2HNO₃(aq) → (x) + NO₂(g) + H₂O(l)؟', ARRAY['Ag₂O(s)','AgNO₃(aq)','AgNO₂(s)','AgO(s)'], 1, 'عند تفاعل الفضة مع حمض النيتريك المركّز → نترات الفضة AgNO₃ + NO₂ + H₂O.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'كيمياء عضوية', 'اختيار من متعدد', 'جزيئات كبيرة تتكوّن من العديد من الوحدات البنائية المتكرّرة:', ARRAY['كيتونات','مونمرات','أميدات','بوليمرات'], 3, 'البوليمر = جزيء ضخم مكوّن من تكرار وحدات صغيرة (مونومرات).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'اتزان', 'اختيار من متعدد', 'ما أثر انخفاض درجة الحرارة لهذا التفاعل الماصّ: N₂O₄ + 55.3 kJ ⇌ 2NO₂؟', ARRAY['زيادة كمية NO₂','زيادة قيمة K_eq','نقص كمية N₂O₄','نقص كمية NO₂'], 3, 'التفاعل ماصّ للحرارة (طاقة على اليسار). انخفاض الحرارة يدفع التفاعل عكسياً → نقص NO₂ (المنتج).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'أحماض', 'اختيار من متعدد', 'أيٌّ من قيم Ka التالية تدلّ على الحمض الأقوى؟', ARRAY['2 × 10⁻²','4 × 10⁻⁶','5 × 10⁻⁵','3 × 10⁻¹²'], 0, 'كلما زادت قيمة Ka زادت قوة الحمض. 2 × 10⁻² هي الأكبر.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'تفاعلات', 'اختيار من متعدد', 'أيُّ العمليات التالية يمكن أن تتم في غياب الأكسجين؟', ARRAY['حلقة كربس','التحلّل السكّري','نقل الإلكترون','تكوين حمض الستريك'], 1, 'التحلّل السكّري (Glycolysis) لا اهوائي يحدث في السيتوبلازم بدون أكسجين.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'جدول دوري', 'اختيار من متعدد', 'عنصر تكافؤه يساوي (+2) يُصنّف هذا العنصر على أنه:', ARRAY['فلز','غاز نبيل','شبه فلز','لافلز'], 0, 'العناصر ذات تكافؤ +2 هي فلزات قلوية ترابية (المجموعة 2).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'أعداد تأكسد', 'اختيار من متعدد', 'عدد تأكسد الكبريت في SO₂:', ARRAY['+4','+2','−4','−2'], 0, 'O = −2 (مجموع −4)، الجزيء متعادل، فالكبريت = +4.', grp_id, NULL, false, 'active', false);
