    VALUES ('tahsili', 'كيمياء', 'حالات المادة', 'اختيار من متعدد', 'أيُّ حالات المادة شكلها وحجمها ثابتان؟', ARRAY['الحالة الصلبة','الحالة السائلة','الحالة الغازية','البلازما'], 0, 'الحالة الصلبة: الشكل والحجم ثابتان (الجسيمات متلاصقة).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
