    VALUES ('tahsili', 'كيمياء', 'تفاعلات', 'اختيار من متعدد', 'ما نوع التفاعل في المعادلة التالية: CaCO₃ → CaO + CO₂؟', ARRAY['تفكك','احتراق','إحلال','تكوين'], 0, 'تفكك (تحلّل) = مركّب واحد ينقسم إلى نواتج أبسط.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'مخاليط', 'اختيار من متعدد', 'أيُّ التالي يُعدّ مخلوطاً معلّقاً؟', ARRAY['سكر المائدة في الماء','ملح المائدة في كيروسين','غاز في سائل','ملح الطعام في الماء'], 1, 'المخلوط المعلّق يحتوي جسيمات لا تذوب وتترسّب مع الوقت. الملح في الكيروسين مثال (لا يذوب).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'حاصل ذائبية', 'اختيار من متعدد', 'أوجد ذائبية يوديد الفضة AgI عند درجة حرارة 298K، إذا كان K_sp = 4 × 10⁻¹². علماً أن AgI(s) ⇌ Ag⁺(aq) + I⁻(aq).', ARRAY['2 × 10⁻⁶','2 × 10⁻¹²','4 × 10⁻⁶','2 × 10⁻¹²'], 0, 'K_sp = s × s = s². إذاً s = √(4 × 10⁻¹²) = 2 × 10⁻⁶ mol/L.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'كيمياء عضوية', 'اختيار من متعدد', 'أيُّ التالي يُعدّ صيغة رباعي كلوريد السيليكون؟', ARRAY['CCl₄','CIH₄','SiCl₄','SeCl₄'], 2, 'رباعي كلوريد السيليكون = SiCl₄.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'تكوين إلكتروني', 'اختيار من متعدد', 'أيُّ التالي يُمثّل عدد المجالات الفرعية في المجال الثانوي p؟', ARRAY['1','3','5','7'], 1, 'المجال p يحتوي 3 أوربيتالات فرعية (px, py, pz).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'محاليل', 'اختيار من متعدد', 'محلول حجمه 2L وعدد مولاته 0.4 فما مولاريّته؟', ARRAY['0.01M','0.02M','0.1M','0.2M'], 3, 'M = n/V = 0.4 / 2 = 0.2 mol/L.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'غازات', 'اختيار من متعدد', 'عيّنة من غاز الأكسجين حجمها 5L وضغطها 1atm ودرجة حرارتها 500K، فإذا زاد الضغط إلى 100atm ودرجة الحرارة 1000K، فإن حجمها يصبح:', ARRAY['0.1 L','0.5 L','0.01 L','0.05 L'], 0, 'P₁V₁/T₁ = P₂V₂/T₂ → (1)(5)/500 = (100)(V₂)/1000 → V₂ = (5 × 1000)/(500 × 100) = 0.1 L.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'مركّبات', 'اختيار من متعدد', 'ما صيغة كلوريد النحاس (II)؟', ARRAY['CuCl','CuCl₂','CuCl₃','CuCl₄'], 1, 'النحاس II = شحنة +2، والكلور −1، فالصيغة CuCl₂.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'مركّبات', 'اختيار من متعدد', 'ما الصيغة الكيميائية لفوسفات الألومنيوم؟', ARRAY['AlPO₄','AlPO₂','Al₄PO₂','AlPO'], 0, 'Al³⁺ مع PO₄³⁻ بنسبة 1:1 → AlPO₄.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'أعداد تأكسد', 'اختيار من متعدد', 'عدد تأكسد الكلور في Ca(ClO₄)₂:', ARRAY['+7','−1','+3','−5'], 0, 'Ca = +2. في ClO₄⁻: O₄ = −8، الأيون = −1، فـ Cl = +7. الكلور في البيركلورات Ca(ClO₄)₂ = +7.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'كيمياء عضوية', 'اختيار من متعدد', 'وفقاً لـIUPAC، ما الاسم النظامي للمركب CH₃CHCH₃ المرتبط بـC₂H₅CHCH₂CHCH₃ والمجموعة الأخيرة CH₃؟', ARRAY['2,6 ثاني ميثيل −3 ثاني ميثيل','2,6 ثاني ميثيل −3 ثاني ميثيل هبتان','3 أيزوبروبيل −5 ميثيل هكسان','2,6 ثاني ميثيل −5 إيثيل هبتان'], 1, 'السلسلة الأطول 7 ذرات (هبتان)، مع تفرّعين ميثيل عند المواقع المناسبة.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'أحماض', 'اختيار من متعدد', 'محلول مائي من كلوريد الأمونيوم PH = 5، قيمة POH له تساوي:', ARRAY['10⁻⁵','10⁻⁹','5','9'], 3, 'PH + POH = 14 → POH = 14 − 5 = 9.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'تكوين إلكتروني', 'اختيار من متعدد', 'عدد الإلكترونات التي يتسع لها المجال الثانوي 4d:', ARRAY['4','6','10','14'], 2, 'المجال d يحتوي 10 إلكترونات (5 أوربيتالات × 2).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'جدول دوري', 'اختيار من متعدد', 'عنصر تكافؤه صفر:', ARRAY['فلز','شبه فلز','لا فلز','خامل'], 3, 'العناصر الخاملة (الغازات النبيلة) لها تكافؤ صفر (مستويات تكافؤ ممتلئة).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'تفاعلات', 'اختيار من متعدد', 'أيُّ التالي يرتبط مع Cl بنسبة 1:1؟', ARRAY['Na','Al','P','Ne'], 0, 'Na⁺ + Cl⁻ → NaCl (نسبة 1:1).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'أحماض', 'اختيار من متعدد', 'ما هي القاعدة المرافقة للتفاعل: CO₃²⁻ + H₂O → HCO₃⁻ + OH⁻؟', ARRAY['OH⁻','H₂O','HCO₃⁻','CO₃²⁻'], 0, 'الماء (حمض هنا) أعطى بروتوناً وتحوّل إلى OH⁻ (القاعدة المرافقة).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'غازات', 'اختيار من متعدد', 'الكتلة المولية للعنصر a = 16 g/mol والكتلة المولية للعنصر b = 64 g/mol. احسب معدل انتشار a عن b.', ARRAY['2','4','16','1/2'], 0, 'قانون جراهام: r_a/r_b = √(M_b/M_a) = √(64/16) = √4 = 2.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'تفاعلات', 'اختيار من متعدد', 'ما نوع التفاعل: AX + BY → AYBX؟', ARRAY['تفكك','تكوين','إحلال مزدوج','إحلال بسيط'], 1, 'اندماج متفاعلين في مركّب واحد → تكوين (Combination/Synthesis).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'أحياء', 'تصنيف', 'اختيار من متعدد', 'مخلوق يعيش على الشاطئ، له زوجان من قرون الاستشعار، ويتنفس بالخياشيم المائية وله عينان مركبتان وخمسة أزواج من الأرجل. أيُّ من الكائنات التالية ينطبق عليها هذا الوصف؟', ARRAY['العنكبيات','الحشرات','المفصليات','القشريات'], 3, 'القشريات (مثل السرطان) تعيش بالماء، خياشيم، قرنا استشعار، 5 أزواج أرجل، عيون مركّبة.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'أحياء', 'تشريح', 'اختيار من متعدد', 'يُعدّ الطحال أحد أجزاء الجهاز:', ARRAY['العضلي','الليمفي','التنفسي','الهضمي'], 1, 'الطحال جزء من الجهاز الليمفي (المناعي).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'أحياء', 'كيمياء حيوية', 'اختيار من متعدد', 'أيُّ المصطلحات التالية تعرف بأنها مادة كيميائية وتتواصل بها بعض المخلوقات ولا تستطيع المفترسات كشفها؟', ARRAY['الهرمونات','الفرمونات','الدهون','البروتينات'], 1, 'الفرمونات إشارات كيميائية بين أفراد النوع نفسه (تواصل).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'أحياء', 'تصنيف', 'اختيار من متعدد', 'أيُّ التالي يُعدّ من السرخسيات؟', ARRAY['العرعر','البرتقال','الخنشار','الصنوبر'], 2, 'الخنشار (الفير) نبات من السرخسيات الحقيقية.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'أحياء', 'وراثة', 'اختيار من متعدد', 'تم تكليف مجموعة من الأطباء بمهمّة الفحص حادث سير. ولم يكن لديهم معلومات أن فصائل دم المصابين. الخيار السليم لهم أن يحملوا معهم من فصائل دم:', ARRAY['A','B','AB','O'], 3, 'فصيلة O− هي المعطي العام (لا تحوي مولّدات A ولا B)، تُعطى لجميع الفصائل.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'أحياء', 'تطوّر', 'اختيار من متعدد', 'عند اكتشاف أن فلامينغو يكثرون بأماكنه قام شخص بالموافقة على هذا الاكتشاف وأخبر نفي ذلك وكلهم لديهم أدلتهم. أيٌّ مما يلي دليل صحيح؟', ARRAY['كل البكتيريا تحتاج إلى الأكسجين','البكتيريا تذهب إلى تركيز الأكسجين الأعلى','بعض البكتيريا هوائية','هناك بكتيريا تعيش بدون أكسجين'], 3, 'البكتيريا متنوّعة: بعضها هوائي ويحتاج O₂، وبعضها لاهوائي يعيش بدون O₂.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'أحياء', 'تشريح', 'اختيار من متعدد', 'أيُّ التراكيب التالية لا يوجد في بطانة الفم للإنسان؟', ARRAY['النواة','الجدار الخلوي','الغشاء الخلوي','السيتوبلازم'], 1, 'الجدار الخلوي يوجد في النبات والبكتيريا والفطريات، أمّا الخلايا الحيوانية فلا تملك جداراً خلوياً.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'أحياء', 'أحياء جزيئية', 'اختيار من متعدد', 'عند دراسته لجزيء DNA وفق قاعدة تشارجاف وجدت أن كمية السايتوسين فيه نسبة الأدنين تساوي 30%، فما نسبة الأدنين؟', ARRAY['%10','%20','%30','%40'], 1, 'قاعدة تشارجاف: %C = %G و %A = %T. مجموع = 100%. إذا %C = 30%، فـ %G = 30% (المجموع 60). %A + %T = 40%. فـ %A = 20%.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'أحياء', 'تكاثر', 'اختيار من متعدد', 'أيُّ العوامل التالية لا يؤثّر في كثافة المخلوقات الحيّة؟', ARRAY['المرض','الافتراس','التنافس','الاحتراق'], 3, 'الاحتراق ليس عاملاً حيوياً مباشراً يؤثر على كثافة الكائنات الحية كالأمراض والافتراس والتنافس.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'أحياء', 'تنفس', 'اختيار من متعدد', 'مرض يكثر يصيب الرئتين ويقلّل فعالية تبادل الغازات بين الهواء والدم:', ARRAY['سرطان الرئة','الإنفلونزا','السل الرئوي','الربو'], 3, 'المصدر يحدّد الجواب د (الربو). الربو يضيّق الشعب الهوائية ويقلّل تبادل الغازات.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'أحياء', 'هرمونات', 'اختيار من متعدد', 'إذا سقط لاعب وتألّم، ماذا يفرز الجسم لتخفيف الألم؟', ARRAY['هرمون النمو','الأدرينالين','الكورتيزول','الإندوفينات'], 3, 'الإندورفينات (الإندوفينات) مسكّنات طبيعية يفرزها الجسم.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'أحياء', 'أحياء جزيئية', 'اختيار من متعدد', 'أظهر التحليل الكيميائي لعينة من الحمض النووي DNA بأن 21% من القواعد النيتروجينية عبارة عن أدنين، فكم نسبة السايتوسين؟', ARRAY['21%','29%','51%','71%'], 1, '%A = %T = 21% → مجموعهما 42%. الباقي 58% للـC+G، فـ %C = 29%.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
