    VALUES ('tahsili', 'أحياء', 'تكيّف', 'اختيار من متعدد', 'أيُّ الحيوانات الآتية تنافس الفرد في التغذية القارّة؟', ARRAY['الغراب','الغزال','الذئب','الصقر'], 0, 'الإنسان قارت — الغراب أيضاً قارت يتنافس معه في موارد الغذاء.', grp_id, NULL, false, 'active', false);
