    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'أحياء', 'بيئة', 'اختيار من متعدد', 'لوحظ في إحدى المزارع أن تركيز السموم في التربة كان مرتفعاً، فتم وضع مواد داخل أنسجة النباتات لمساعدتها على امتصاص السموم وطرحها خارج البيئة. ما الاسم الذي يطلق على هذه العملية؟', ARRAY['زيادة حيوية','إثراء غذائي','معالجة حيوية','وقاية حيوية'], 2, 'المعالجة الحيوية (Bioremediation): استخدام الكائنات الحية لإزالة الملوّثات.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
